package com.example.lessondesign.dao; import com.example.lessondesign.bean.TeacherDesign; import org.apache.ibatis.annotations.*; import java.util.*; @Mapper public interface TeacherDesignDao { @Insert("INSERT INTO teacher_design (course_name,teacher_id,content,s_level,created_time) VALUES (#{courseName},#{teacherId},#{content},#{sLevel},#{createdTime})") @Options(useGeneratedKeys=true,keyProperty="id") int insert(TeacherDesign d); @Select("SELECT * FROM teacher_design WHERE teacher_id=#{tid}") List<TeacherDesign> findByTeacherId(@Param("tid") String tid); }